        a[0] * b[1] - a[1] * b[0],
    )


def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)


def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))


def _computed_normal(v1, v2, v3):
    """Return the unit normal implied by vertex winding order, or None if degenerate."""
    cn = _cross(_sub(v2, v1), _sub(v3, v1))
    mag = _magnitude(cn)
    if mag == 0:
        return None
    return (cn[0] / mag, cn[1] / mag, cn[2] / mag)


def _is_normal_consistent(declared, computed, threshold_deg=NORMAL_ANGLE_THRESHOLD_DEG):
    """Return True if the angle between declared and computed normals is < threshold."""
    dec_mag = _magnitude(declared)
    if dec_mag == 0:
        # declared normal is zero vector — treat as zero-normal (valid placeholder in some tools)
        return True
